import scala.math._

def solve(nums: Array[Long]): Long = {
  val n = nums.length - 1
  val isPrime = Array.fill(n + 1)(true)
  isPrime(0) = false
  isPrime(1) = false
  for (i <- 2 to math.sqrt(n).toInt) {
